   345→              >
   346→                Delete
   347→              </button>
   348→            </div>
   349→          )}
   350→        </div>
   351→      </div>
   352→
   353→      {task.description && (
   354→        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-2 line-clamp-2">
   355→          {task.description}
   356→        </p>
   357→      )}
   358→
   359→      <div className="flex items-center gap-2 flex-wrap">
   360→        {/* Priority Badge */}
   361→        <span className="text-xs px-2 py-0.5 rounded bg-neutral-100 dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary">
   362→          {priorityLabels[task.priority]}
   363→        </span>
   364→
   365→        {/* Due Date with overdue/due soon indicators */}
   366→        {task.dueDate && (() => {
   367→          const dueDate = new Date(task.dueDate);
   368→          const now = new Date();
   369→          const daysUntilDue = Math.ceil((dueDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
   370→          const isOverdue = daysUntilDue < 0;
   371→          const isDueSoon = daysUntilDue >= 0 && daysUntilDue <= 3;
   372→
   373→          return (
   374→            <span className={`text-xs px-2 py-0.5 rounded ${
   375→              isOverdue
   376→                ? 'bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark'
   377→                : isDueSoon
   378→                ? 'bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark'
   379→                : 'bg-neutral-100 dark:bg-neutral-800 text-accent-blue'
   380→            }`}>
   381→              📅 {dueDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
   382→            </span>
   383→          );
   384→        })()}
   385→
   386→        {/* P1: Recurring Task Indicator */}
   387→        {(task.recurrence || task.recurrenceId) && (
   388→          <span
   389→            className="text-xs px-2 py-0.5 rounded bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue dark:text-accent-blue-hover font-medium"
   390→            title={
   391→              task.isRecurringParent
   392→                ? `Recurring task (${task.recurrence?.frequency})${task.nextOccurrence ? ` • Next: ${task.nextOccurrence}` : ''}`
   393→                : 'Instance of recurring task'
   394→            }
   395→          >
