   432→          >
   433→            #{tag}
   434→          </span>
   435→        ))}
   436→
   437→        {/* Custom Fields (P1 Feature) */}
   438→        {activeCustomFields.map(({ field, value }) => (
   439→          <span
   440→            key={field.id}
   441→            className="text-xs px-2 py-0.5 rounded bg-accent-magenta/10 dark:bg-accent-magenta/20 text-accent-magenta dark:text-accent-magenta-hover font-medium"
   442→            title={`${field.name}: ${formatCustomFieldValue(field, value)}`}
   443→          >
   444→            {field.name}: {formatCustomFieldValue(field, value)}
   445→          </span>
   446→        ))}
   447→
   448→        {/* Dependency Indicators (PHASE 5 PART 6) */}
   449→        {(() => {
   450→          const blockers = getBlockers(task.id);
   451→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   452→
   453→          if (incompleteBlockers.length > 0) {
   454→            return (
   455→              <span
   456→                onClick={(e) => {
   457→                  e.stopPropagation();
   458→                  if (onCardClick) {
   459→                    onCardClick(task);
   460→                  }
   461→                }}
   462→                className="text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark hover:opacity-80"
   463→                title={`Blocked by ${incompleteBlockers.length} task(s)`}
   464→              >
   465→                🔒 Blocked by {incompleteBlockers.length}
   466→              </span>
   467→            );
   468→          }
   469→
   470→          const blocked = getBlocked(task.id);
   471→          if (blocked.length > 0) {
   472→            return (
   473→              <span
   474→                onClick={(e) => {
   475→                  e.stopPropagation();
   476→                  if (onCardClick) {
   477→                    onCardClick(task);
   478→                  }
   479→                }}
   480→                className="text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600"
   481→                title={`Blocking ${blocked.length} task(s)`}
   482→              >
   483→                ⚠️ Blocks {blocked.length}
   484→              </span>
   485→            );
   486→          }
   487→
   488→          return null;
   489→        })()}
   490→
   491→        {/* Subtask Progress Badge */}
   492→        {task.subtasks && task.subtasks.length > 0 && (() => {
   493→          const completedCount = task.subtasks.filter(st => st.completed).length;
   494→          const totalCount = task.subtasks.length;
   495→          const isComplete = completedCount === totalCount;
   496→
   497→          return (
   498→            <span
   499→              onClick={(e) => {
   500→                e.stopPropagation();
   501→                if (onCardClick) {
   502→                  onCardClick(task, 'subtasks');
   503→                }
   504→              }}
   505→              className={`text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 ${
   506→                isComplete
   507→                  ? 'bg-status-success text-white hover:bg-status-success/90'
   508→                  : completedCount > 0
   509→                  ? 'bg-accent-blue text-white hover:bg-accent-blue/90'
   510→                  : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
   511→              }`}
   512→            >
   513→              ✓ {completedCount}/{totalCount} subtasks
   514→            </span>
   515→          );
   516→        })()}
   517→
   518→        {/* Assignee Avatars - Phase 3.1 */}
   519→        {assignedMembers.length > 0 && (
   520→          <div className="flex items-center -space-x-1.5">
   521→            {assignedMembers.slice(0, 3).map((member, index) => (
   522→              <div
   523→                key={member.id}
   524→                className="w-6 h-6 rounded-full flex items-center justify-center text-white font-bold text-[10px] border-2 border-surface-light dark:border-surface-dark-elevated shrink-0"
   525→                style={{
   526→                  backgroundColor: member.avatarColor,
   527→                  zIndex: assignedMembers.length - index
   528→                }}
   529→                title={member.name}
   530→              >
   531→                {member.initials}
   532→              </div>
   533→            ))}
   534→            {assignedMembers.length > 3 && (
   535→              <div
   536→                className="w-6 h-6 rounded-full flex items-center justify-center text-xs font-medium bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary border-2 border-surface-light dark:border-surface-dark-elevated"
   537→                title={`+${assignedMembers.length - 3} more`}
   538→              >
   539→                +{assignedMembers.length - 3}
   540→              </div>
   541→            )}
   542→          </div>
   543→        )}
   544→
   545→        {/* Attachment Badge - Phase 3.2 */}
   546→        {task.attachments && task.attachments.length > 0 && (
   547→          <span
   548→            className="flex items-center gap-1 text-xs text-text-light-secondary dark:text-text-dark-secondary"
   549→            title={`${task.attachments.length} attachment${task.attachments.length > 1 ? 's' : ''}`}
   550→          >
   551→            <Paperclip className="w-3.5 h-3.5" />
   552→            {task.attachments.length}
   553→          </span>
   554→        )}
   555→      </div>
   556→      </div>
   557→
   558→      {/* Delete Confirmation Dialog */}
   559→      {showDeleteDialog && (
   560→        <ConfirmDialog
   561→          isOpen={true}
   562→          onClose={cancelDelete}
   563→          onConfirm={confirmDelete}
   564→          title="Delete Task"
   565→          message={`Are you sure you want to delete "${task.title}"? This action cannot be undone.`}
   566→          variant="danger"
   567→        />
   568→      )}
   569→    </div>
   570→  );
   571→};
