   573→// Memoize the component to prevent unnecessary re-renders
   574→// Only re-render if task, isDragging, or isSelected props change
   575→export const KanbanCard = memo(KanbanCardComponent, (prevProps, nextProps) => {
   576→  const prevAssignees = prevProps.task.assignees || [];
   577→  const nextAssignees = nextProps.task.assignees || [];
   578→  const prevAttachments = prevProps.task.attachments || [];
   579→  const nextAttachments = nextProps.task.attachments || [];
   580→  const prevCustomFields = prevProps.task.customFields || {};
   581→  const nextCustomFields = nextProps.task.customFields || {};
   582→
   583→  return (
   584→    prevProps.task.id === nextProps.task.id &&
   585→    prevProps.task.title === nextProps.task.title &&
   586→    prevProps.task.description === nextProps.task.description &&
   587→    prevProps.task.priority === nextProps.task.priority &&
   588→    prevProps.task.dueDate === nextProps.task.dueDate &&
   589→    prevProps.task.startDate === nextProps.task.startDate &&
   590→    prevProps.task.tags.length === nextProps.task.tags.length &&
   591→    prevAssignees.length === nextAssignees.length &&
   592→    prevAttachments.length === nextAttachments.length &&
   593→    prevProps.task.coverMode === nextProps.task.coverMode &&
   594→    Object.keys(prevCustomFields).length === Object.keys(nextCustomFields).length &&
   595→    prevProps.isDragging === nextProps.isDragging &&
   596→    prevProps.isSelected === nextProps.isSelected
   597→  );
