     1→import { create } from 'zustand';
     2→import { persist } from 'zustand/middleware';
     3→import type { DailyNotesSettings } from '../services/dailyNotes';
     4→import { DEFAULT_DAILY_NOTES_SETTINGS } from '../services/dailyNotes';
     5→import type { FieldDefinition } from '../types/customFields';
     6→import type { Member } from '../types';
     7→import { nanoid } from 'nanoid';
     8→
     9→export type TimeFormat = '12h' | '24h';
    10→export type TemperatureUnit = 'fahrenheit' | 'celsius';
    11→
    12→export interface CustomFieldDefinitions {
    13→  tasks: FieldDefinition[];
    14→  notes: FieldDefinition[];
    15→}
    16→
    17→export interface SettingsState {
    18→  // Display preferences
    19→  timeFormat: TimeFormat;
    20→  temperatureUnit: TemperatureUnit;
    21→
    22→  // Daily Notes
    23→  dailyNotes: DailyNotesSettings;
    24→
    25→  // Custom Fields (P2 #3)
    26→  customFieldDefinitions: CustomFieldDefinitions;
    27→
    28→  // Task Management (Phase 1.2)
    29→  autoShiftDependentTasks: boolean; // Auto-shift dependent tasks when dates change
    30→
    31→  // Kanban WIP Limits (Phase 3.3)
    32→  enforceWipLimits: boolean; // Enforce WIP limits strictly (prevent moves vs warnings)
    33→
    34→  // Team Members (Phase 3.1)
    35→  members: Member[];
    36→
    37→  // Actions
    38→  setTimeFormat: (format: TimeFormat) => void;
    39→  setTemperatureUnit: (unit: TemperatureUnit) => void;
    40→  setDailyNotesSettings: (settings: Partial<DailyNotesSettings>) => void;
    41→  setAutoShiftDependentTasks: (enabled: boolean) => void;
    42→  setEnforceWipLimits: (enabled: boolean) => void;
    43→
    44→  // Custom field actions
    45→  addFieldDefinition: (target: 'tasks' | 'notes', field: Omit<FieldDefinition, 'id' | 'createdAt' | 'updatedAt'>) => void;
    46→  updateFieldDefinition: (target: 'tasks' | 'notes', fieldId: string, changes: Partial<FieldDefinition>) => void;
    47→  deleteFieldDefinition: (target: 'tasks' | 'notes', fieldId: string) => void;
    48→
    49→  // Member actions
    50→  addMember: (member: Omit<Member, 'id' | 'createdAt'>) => void;
    51→  updateMember: (id: string, updates: Partial<Member>) => void;
    52→  deleteMember: (id: string) => void;
    53→}
    54→
    55→/**
    56→ * Global Settings Store
    57→ *
    58→ * Persisted user preferences for:
    59→ * - Time format (12h/24h)
    60→ * - Temperature unit (F/C)
    61→ * - Daily notes configuration
    62→ *
    63→ * Used by:
    64→ * - HeaderClock component
    65→ * - Weather widgets (WeatherMap, Weather, WeatherForecast)
    66→ * - TimeTracking page (if applicable)
    67→ * - Daily notes feature (Notes page, Sidebar)
    68→ */
    69→export const useSettingsStore = create<SettingsState>()(
    70→  persist(
    71→    (set) => ({
    72→      // Default: 12-hour time, Fahrenheit
    73→      timeFormat: '12h',
    74→      temperatureUnit: 'fahrenheit',
    75→      dailyNotes: DEFAULT_DAILY_NOTES_SETTINGS,
    76→      customFieldDefinitions: {
    77→        tasks: [],
    78→        notes: [],
    79→      },
    80→      autoShiftDependentTasks: true, // Default: enabled
    81→      enforceWipLimits: false, // Default: soft limits (warnings only)
    82→      members: [], // Default: no members
    83→
    84→      setTimeFormat: (format) => set({ timeFormat: format }),
    85→      setTemperatureUnit: (unit) => set({ temperatureUnit: unit }),
    86→      setDailyNotesSettings: (settings) =>
    87→        set((state) => ({
    88→          dailyNotes: { ...state.dailyNotes, ...settings },
    89→        })),
    90→      setAutoShiftDependentTasks: (enabled) => set({ autoShiftDependentTasks: enabled }),
    91→      setEnforceWipLimits: (enabled) => set({ enforceWipLimits: enabled }),
    92→
    93→      // Custom field management
    94→      addFieldDefinition: (target, field) =>
    95→        set((state) => {
    96→          const now = new Date();
    97→          const newField: FieldDefinition = {
    98→            ...field,
    99→            id: nanoid(),
   100→            createdAt: now,
   101→            updatedAt: now,
   102→          };
   103→
   104→          return {
   105→            customFieldDefinitions: {
   106→              ...state.customFieldDefinitions,
   107→              [target]: [...state.customFieldDefinitions[target], newField],
   108→            },
   109→          };
   110→        }),
   111→
   112→      updateFieldDefinition: (target, fieldId, changes) =>
   113→        set((state) => ({
   114→          customFieldDefinitions: {
   115→            ...state.customFieldDefinitions,
   116→            [target]: state.customFieldDefinitions[target].map((field) =>
   117→              field.id === fieldId
   118→                ? { ...field, ...changes, updatedAt: new Date() }
   119→                : field
   120→            ),
   121→          },
   122→        })),
   123→
   124→      deleteFieldDefinition: (target, fieldId) =>
   125→        set((state) => ({
   126→          customFieldDefinitions: {
   127→            ...state.customFieldDefinitions,
   128→            [target]: state.customFieldDefinitions[target].filter(
   129→              (field) => field.id !== fieldId
   130→            ),
   131→          },
   132→        })),
   133→
   134→      // Member management
   135→      addMember: (member) =>
   136→        set((state) => {
   137→          const newMember: Member = {
   138→            ...member,
