        <span>➕</span>
        <span>Create Custom Field</span>
      </button>

      {/* Field List */}
      {activeFields.length > 0 ? (
        <div className="space-y-3">
          {activeFields.map((field) => (
            <FieldListItem
              key={field.id}
              field={field}
              onDelete={handleDeleteField}
              onUpdate={handleUpdateField}
            />
          ))}
        </div>
      ) : (
        <div className="p-8 text-center bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-dashed border-border-light dark:border-border-dark">
          <p className="text-lg text-text-light-secondary dark:text-text-dark-secondary mb-2">
            No custom fields yet
          </p>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Click "Create Custom Field" above to add your first {activeTab === 'tasks' ? 'task' : 'note'}{' '}
            field.
          </p>
        </div>
      )}

      {/* Info Box */}
      <div className="mt-6 p-4 bg-status-info-bg dark:bg-status-info-bg-dark border border-status-info-border dark:border-status-info-border-dark rounded-lg">
        <p className="text-xs text-status-info-text dark:text-status-info-text-dark">
          <strong>💡 Tip:</strong> Custom fields are great for tracking domain-specific metadata like Bug IDs,
          Sprint numbers, Client names, Energy levels, and more. Field values can be set on individual{' '}
          {activeTab === 'tasks' ? 'tasks' : 'notes'}.
        </p>
      </div>

      {/* Create Modal */}
      <CreateFieldModal
        isOpen={showCreateModal}
        onClose={() => setShowCreateModal(false)}
        onSave={handleCreateField}
        target={activeTab}
      />
    </div>
  );
}

import React from 'react';
import type { FieldDefinition } from '../types/customFields';

/**
 * CustomFieldDisplay Component
 *
 * Compact display component for custom field values.
 * Used in Kanban cards and List view.
 *
 * Features:
 * - Handles all field types (text, number, checkbox, date, select)
 * - Two variants: 'card' (badge style) and 'list' (plain text)
 * - Semantic token styling for dark mode
 * - ARIA labels for accessibility
 */

interface CustomFieldDisplayProps {
  field: FieldDefinition;
  value: any;
  variant?: 'card' | 'list';
  className?: string;
}

export function CustomFieldDisplay({
  field,
  value,
  variant = 'card',
  className = ''
}: CustomFieldDisplayProps) {
  // Don't render if value is empty
  if (value === null || value === undefined || value === '') {
    if (variant === 'list') {
      // In list view, show em dash for empty cells
      return <span className="text-text-light-secondary dark:text-text-dark-secondary">—</span>;
    }
    // In card view, don't render anything
    return null;
  }

  const formatValue = (): string => {
    switch (field.type) {
      case 'date':
        const date = new Date(value);
        return date.toLocaleDateString('en-US', {
          month: 'short',
          day: 'numeric',
          year: variant === 'list' ? 'numeric' : undefined
        });
      case 'checkbox':
        return value ? '✓' : '✗';
      case 'number':
        return String(value);
      case 'text':
      case 'select':
      default:
        return String(value);
    }
  };

  const formattedValue = formatValue();

  // Card variant: Badge style with field name and value
  if (variant === 'card') {
    return (
      <span
        className={`text-xs px-2 py-0.5 rounded bg-accent-magenta/10 dark:bg-accent-magenta/20 text-accent-magenta dark:text-accent-magenta-hover font-medium ${className}`}
        title={`${field.name}: ${formattedValue}`}
        aria-label={`${field.name}: ${formattedValue}`}
      >
        {field.type === 'checkbox' ? (
          // Checkbox: Show checkmark + name
          <>{formattedValue} {field.name}</>
        ) : (
          // Other types: Show name: value
          <>{field.name}: {formattedValue}</>
        )}
      </span>
    );
  }

  // List variant: Plain text for table cells
  return (
    <span
      className={`text-sm text-text-light-secondary dark:text-text-dark-secondary ${className}`}
      aria-label={`${field.name}: ${formattedValue}`}
    >
      {formattedValue}
    </span>
  );
}
